OPENQASM 3.0;
include "stdgates.inc";

// F — True Phi (Ry=103.66°) — GoldenGHZ Validation
// Experiment: GOLDEN_GHZ_Tycho_Verification_10k_Shots
// Angle: 1.8092083026 rad = 103.6600 deg

qubit[4] q;
bit[4] c;

// State preparation: Ry(theta) on q[0]
ry(1.809208302617322) q[0];

// CNOT entanglement chain: creates GHZ state
cx q[0], q[1];
cx q[1], q[2];
cx q[2], q[3];

// Full 4-qubit measurement
c[0] = measure q[0];
c[1] = measure q[1];
c[2] = measure q[2];
c[3] = measure q[3];

